  const fallbackVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1 }
  }

  return (
    <motion.div
      variants={fallbackVariants}
      initial="hidden"
      animate="visible"
      transition={{ duration: 0.3 }}
