import React, { useState, useRef, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Eye, EyeOff, Shield, AlertTriangle } from 'lucide-react'
import Input from '@/components/ui/Input'
import { sanitizeInput, isValidEmail, isValidPhone } from '@/utils/security'

const SecureInput = ({ 
  type = 'text',
  label,
  placeholder,
  value,
  onChange,
  onBlur,
  error,
  required = false,
  maxLength = 1000,
  validation,
  sanitize = true,
  showStrength = false,
  showToggle = false,
  className = '',
  ...props 
}) => {
  const [showPassword, setShowPassword] = useState(false)
  const [isValid, setIsValid] = useState(true)
  const [validationMessage, setValidationMessage] = useState('')
  const [isFocused, setIsFocused] = useState(false)
  const inputRef = useRef(null)

  // Handle input change with sanitization
  const handleChange = (e) => {
    let newValue = e.target.value

    // Sanitize input if enabled
    if (sanitize) {
      newValue = sanitizeInput(newValue, {
        allowHTML: false,
        maxLength
      })
    }

    // Call original onChange
    if (onChange) {
      const syntheticEvent = {
        ...e,
        target: {
          ...e.target,
          value: newValue
        }
      }
      onChange(syntheticEvent)
    }
  }

  // Validation on blur
  const handleBlur = (e) => {
    setIsFocused(false)

    let newValue = e.target.value
    if (sanitize) {
      newValue = sanitizeInput(newValue)
    }

    // Built-in validation
    if (type === 'email') {
      const valid = isValidEmail(newValue)
      setIsValid(valid)
      setValidationMessage(valid ? '' : 'Ge├ğerli bir e-posta adresi girin')
    } else if (type === 'tel') {
      const valid = isValidPhone(newValue)
      setIsValid(valid)
      setValidationMessage(valid ? '' : 'Ge├ğerli bir telefon numaras─▒ girin')
    } else if (validation) {
      const result = validation(newValue)
      setIsValid(result.valid)
      setValidationMessage(result.message || '')
    } else {
      setIsValid(true)
      setValidationMessage('')
    }

    if (onBlur) {
      onBlur(e)
    }
  }

  // Password strength calculation
  const getPasswordStrength = () => {
    if (type !== 'password' || !showStrength) return null

    const { checkPasswordStrength } = require('@/utils/security')
    return checkPasswordStrength(value || '')
  }

  const passwordStrength = getPasswordStrength()

  // Get input type
  const getInputType = () => {
    if (type === 'password' && showToggle) {
      return showPassword ? 'text' : 'password'
    }
    return type
  }

  // Get security icon
  const getSecurityIcon = () => {
    if (!isFocused && !error) return null

    if (error) {
      return <AlertTriangle className="w-4 h-4 text-red-400" />
    }

    if (type === 'password' && showStrength && value) {
      const strengthColor = passwordStrength?.strength === 'weak' ? 'text-red-400' :
                          passwordStrength?.strength === 'medium' ? 'text-yellow-400' :
                          passwordStrength?.strength === 'strong' ? 'text-green-400' :
                          'text-green-500'
      return <Shield className={`w-4 h-4 ${strengthColor}`} />
    }

    if (isValid && value) {
      return <Shield className="w-4 h-4 text-green-400" />
    }

    return null
  }

  return (
    <div className={`relative ${className}`}>
      <Input
        ref={inputRef}
        type={getInputType()}
        label={label}
        placeholder={placeholder}
        value={value}
        onChange={handleChange}
        onBlur={handleBlur}
        onFocus={() => setIsFocused(true)}
        maxLength={maxLength}
        required={required}
        error={error || validationMessage}
        icon={getSecurityIcon()}
        className={`${!isValid ? 'border-red-500' : ''} ${type === 'password' && showToggle ? 'pr-12' : ''}`}
        {...props}
      />

      {/* Password toggle */}
      {type === 'password' && showToggle && (
        <button
          type="button"
          onClick={() => setShowPassword(!showPassword)}
          className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-white transition-colors"
          aria-label={showPassword ? '┼Şifreyi gizle' : '┼Şifreyi g├Âster'}
        >
          {showPassword ? (
            <EyeOff className="w-4 h-4" />
          ) : (
            <Eye className="w-4 h-4" />
          )}
        </button>
      )}

      {/* Password strength indicator */}
      {type === 'password' && showStrength && value && (
        <motion.div
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: 'auto' }}
          className="mt-2"
        >
          <div className="flex items-center justify-between text-xs">
            <span className="text-gray-400">┼Şifre g├╝c├╝:</span>
            <span className={`font-medium ${
              passwordStrength?.strength === 'weak' ? 'text-red-400' :
              passwordStrength?.strength === 'medium' ? 'text-yellow-400' :
              passwordStrength?.strength === 'strong' ? 'text-green-400' :
              'text-green-500'
            }`}>
              {passwordStrength?.strength === 'weak' ? 'Zay─▒f' :
               passwordStrength?.strength === 'medium' ? 'Orta' :
               passwordStrength?.strength === 'strong' ? 'G├╝├ğl├╝' :
               '├çok G├╝├ğl├╝'}
            </span>
          </div>

          {/* Strength bar */}
          <div className="mt-1 h-2 bg-gray-700 rounded-full overflow-hidden">
            <motion.div
              initial={{ width: 0 }}
              animate={{ width: `${(passwordStrength?.score || 0) * 16.67}%` }}
              transition={{ duration: 0.3 }}
              className={`h-full ${
                passwordStrength?.strength === 'weak' ? 'bg-red-500' :
                passwordStrength?.strength === 'medium' ? 'bg-yellow-500' :
                passwordStrength?.strength === 'strong' ? 'bg-green-500' :
                'bg-green-600'
              }`}
            />
          </div>

          {/* Feedback */}
          {passwordStrength?.feedback && passwordStrength.feedback.length > 0 && (
            <div className="mt-2 text-xs text-gray-400">
              {passwordStrength.feedback.join(', ')}
            </div>
          )}
        </motion.div>
      )}
    </div>
  )
}

export default SecureInput

import React from 'react'
import { motion } from 'framer-motion'
import { Shield, AlertTriangle, RefreshCw } from 'lucide-react'
import { useSecurityLogger } from '@/hooks/useSecurityProtections'
import Card from '@/components/ui/Card'
import Button from '@/components/ui/Button'

class SecurityBoundary extends React.Component {
  constructor(props) {
    super(props)
    this.state = { 
      hasError: false, 
      error: null, 
      errorInfo: null,
      errorType: null
    }
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error }
  }

  componentDidCatch(error, errorInfo) {
    const { logSecurityEvent } = useSecurityLogger()

    // Analyze error type
    const errorType = this.analyzeError(error)

    // Log security event
    logSecurityEvent('component_error', {
      error: error.message,
      stack: error.stack,
      componentStack: errorInfo.componentStack,
      errorType,
      severity: errorType === 'security' ? 'high' : 'medium'
    })

    this.setState({
      error,
      errorInfo,
      errorType
    })
  }

  analyzeError = (error) => {
    const message = error.message.toLowerCase()

    // Security-related errors
    if (message.includes('xss') || 
        message.includes('injection') || 
        message.includes('csrf') ||
        message.includes('unauthorized') ||
        message.includes('forbidden')) {
      return 'security'
    }

    // Network errors
    if (message.includes('network') || 
        message.includes('fetch') ||
        message.includes('cors')) {
      return 'network'
    }

    // Validation errors
    if (message.includes('validation') || 
        message.includes('invalid') ||
        message.includes('required')) {
      return 'validation'
    }

    // Default
    return 'general'
  }

  handleReset = () => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      errorType: null
    })
  }

  handleReportError = () => {
    const { error, errorInfo, errorType } = this.state

    // Create error report
    const errorReport = {
      type: errorType,
      message: error.message,
      stack: error.stack,
      componentStack: errorInfo?.componentStack,
      userAgent: navigator.userAgent,
      timestamp: new Date().toISOString(),
      url: window.location.href
    }

    // Send to error reporting service
    import('@/services/api').then(({ default: api }) => {
      api.post('/security/report-error', errorReport).catch(() => {})
    }).catch(() => {})
  }

  render() {
    if (this.state.hasError) {
      const { error, errorType } = this.state

      return (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="min-h-screen flex items-center justify-center p-4"
        >
          <Card glass className="max-w-md w-full">
            <div className="text-center space-y-6">
              {/* Error Icon */}
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                transition={{ type: "spring", damping: 20, stiffness: 300 }}
                className={`w-16 h-16 rounded-full flex items-center justify-center mx-auto ${
                  errorType === 'security' 
                    ? 'bg-red-500/20' 
                    : errorType === 'network'
                    ? 'bg-yellow-500/20'
                    : 'bg-blue-500/20'
                }`}
              >
                {errorType === 'security' ? (
                  <Shield className="w-8 h-8 text-red-400" />
                ) : errorType === 'network' ? (
                  <AlertTriangle className="w-8 h-8 text-yellow-400" />
                ) : (
                  <AlertTriangle className="w-8 h-8 text-blue-400" />
                )}
              </motion.div>

              {/* Error Message */}
              <div className="space-y-4">
                <h2 className="text-xl font-bold text-white">
                  {errorType === 'security' 
                    ? 'G├╝venlik Hatas─▒'
                    : errorType === 'network'
                    ? 'Ba─şlant─▒ Hatas─▒'
                    : 'Beklenmedik Hata'
                  }
                </h2>

                <p className="text-gray-300 leading-relaxed">
                  {errorType === 'security' 
                    ? 'G├╝venlik ├Ânlemleri nedeniyle i┼şlem engellendi. L├╝tfen sayfay─▒ yenileyin veya destekle ileti┼şime ge├ğin.'
                    : errorType === 'network'
                    ? 'A─ş ba─şlant─▒s─▒ kurulamad─▒. ─░nternet ba─şlant─▒n─▒z─▒ kontrol edin.'
                    : 'Uygulamada beklenmedik bir hata olu┼ştu.'
                  }
                </p>

                {/* Error Details (Development) */}
                {process.env.NODE_ENV === 'development' && (
                  <details className="text-left">
                    <summary className="text-sm text-gray-400 cursor-pointer hover:text-white transition-colors">
                      Hata Detaylar─▒ (Geli┼ştirici Modu)
                    </summary>
                    <pre className="mt-2 p-3 bg-gray-800 rounded text-xs text-red-400 overflow-auto">
                      {error.stack}
                    </pre>
                  </details>
                )}
              </div>

              {/* Actions */}
              <div className="flex flex-col sm:flex-row gap-3">
                <Button
                  onClick={this.handleReset}
                  className="flex-1"
                >
                  <RefreshCw className="w-4 h-4 mr-2" />
                  Tekrar Dene
                </Button>

                <Button
                  variant="secondary"
                  onClick={this.handleReportError}
                  className="flex-1"
                >
                  Hata Bildir
                </Button>
              </div>

              {/* Support Info */}
              <div className="pt-4 border-t border-gray-700">
                <p className="text-sm text-gray-400">
                  Sorun devam ediyorsa: 
                  <a 
                    href="mailto:support@axiar.io" 
                    className="text-cyan-400 hover:text-cyan-300 transition-colors"
                  >
                    support@axiar.io
                  </a>
                </p>
              </div>
            </div>
          </Card>
        </motion.div>
      )
    }

    return this.props.children
  }
}

