import React from 'react'
import { motion } from 'framer-motion'
import { cn } from '@/utils/cn'

const Skeleton = ({ 
  className = '', 
  variant = 'default',
  lines = 1,
  height 
}) => {
  const baseClasses = 'relative overflow-hidden bg-white/5 rounded-lg'

  const variants = {
    default: baseClasses,
    text: `${baseClasses} h-4`,
    avatar: `${baseClasses} w-12 h-12 rounded-full`,
    button: `${baseClasses} h-10`,
    card: baseClasses,
    line: `${baseClasses} h-2`
  }

  // Shimmer animation
  const shimmerVariants = {
    initial: { x: '-100%' },
    animate: { 
      x: '100%',
      transition: {
        repeat: Infinity,
        duration: 1.5,
        ease: "linear"
      }
    }
  }

  const renderSkeleton = () => {
    const commonClasses = cn(className, variants[variant])

    const Shimmer = () => (
      <motion.div
        variants={shimmerVariants}
        initial="initial"
        animate="animate"
        className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent"
      />
    )

    switch (variant) {
      case 'lines':
        return (
          <div className={cn('space-y-3', className)}>
            {Array.from({ length: lines }).map((_, index) => (
              <div key={index} className={cn(variants.line, 'relative overflow-hidden')}>
                <Shimmer />
              </div>
            ))}
          </div>
        )

      default:
        const currentVariantClass = variant === 'card' 
          ? cn(variants.card, height || 'h-32')
          : variant === 'avatar' ? variants.avatar
          : variants[variant] || variants.default

        return (
          <div className={cn(currentVariantClass, 'relative overflow-hidden', className)}>
            <Shimmer />
          </div>
        )
    }
  }

  return renderSkeleton()
}

export default Skeleton

import React, { useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { X, CheckCircle, AlertTriangle, Info } from 'lucide-react'

const Toast = ({ 
  toast, 
  position = 'top-right',
  autoClose = 5000,
  onClose 
}) => {
  const [isVisible, setIsVisible] = React.useState(true)

  useEffect(() => {
    if (autoClose > 0) {
      const timer = setTimeout(() => {
        setIsVisible(false)
        onClose?.()
      }, autoClose)

      return () => clearTimeout(timer)
    }
  }, [autoClose, onClose])

  const handleClose = () => {
    setIsVisible(false)
    onClose?.()
  }

  const getIcon = () => {
    switch (toast.type) {
      case 'success':
        return <CheckCircle className="w-5 h-5 text-green-400" />
      case 'error':
        return <AlertTriangle className="w-5 h-5 text-red-400" />
      case 'warning':
        return <AlertTriangle className="w-5 h-5 text-yellow-400" />
      default:
        return <Info className="w-5 h-5 text-blue-400" />
    }
  }

  const getTypeStyles = () => {
    switch (toast.type) {
      case 'success':
        return 'bg-green-500/20 border-green-500/30 text-green-400'
      case 'error':
        return 'bg-red-500/20 border-red-500/30 text-red-400'
      case 'warning':
        return 'bg-yellow-500/20 border-yellow-500/30 text-yellow-400'
      default:
        return 'bg-blue-500/20 border-blue-500/30 text-blue-400'
    }
  }

  const getPositionClasses = () => {
    const positions = {
      'top-right': 'top-4 right-4',
      'top-left': 'top-4 left-4',
      'bottom-right': 'bottom-4 right-4',
      'bottom-left': 'bottom-4 left-4',
      'top-center': 'top-4 left-1/2 transform -translate-x-1/2',
      'bottom-center': 'bottom-4 left-1/2 transform -translate-x-1/2'
    }
    return positions[position] || positions['top-right']
  }

  const toastVariants = {
    hidden: { 
      opacity: 0, 
      scale: 0.8,
      y: 50
    },
    visible: { 
      opacity: 1, 
      scale: 1,
      y: 0
    },
    exit: { 
      opacity: 0, 
      scale: 0.8,
      y: -50
    }
  }

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          variants={toastVariants}
          initial="hidden"
          animate="visible"
          exit="exit"
          transition={{ 
            type: "spring", 
            damping: 25, 
            stiffness: 400 
          }}
          className={`fixed z-50 ${getPositionClasses()}`}
        >
          <div className={`glass border ${getTypeStyles()} rounded-lg p-4 min-w-80 max-w-md shadow-2xl`}>
            <div className="flex items-start space-x-3">
              {/* Icon */}
              <div className="flex-shrink-0 mt-0.5">
                {getIcon()}
              </div>

              {/* Content */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between">
                  <h4 className="text-sm font-semibold text-white">
                    {toast.title}
                  </h4>

                  {/* Close Button */}
                  <button
                    onClick={handleClose}
                    className="flex-shrink-0 ml-4 text-gray-400 hover:text-white transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>

                {toast.description && (
                  <p className="text-sm text-gray-300 mt-1 leading-relaxed">
                    {toast.description}
                  </p>
                )}
              </div>
            </div>

            {/* Progress Bar (if applicable) */}
            {toast.progress !== undefined && (
              <div className="mt-3">
                <div className="flex items-center justify-between text-xs text-gray-400 mb-1">
                  <span>─░lerleme</span>
                  <span>{Math.round(toast.progress)}%</span>
                </div>
                <div className="w-full bg-gray-700 rounded-full h-2 overflow-hidden">
                  <motion.div
                    className="h-full bg-gradient-to-r from-cyan-500 to-blue-500 rounded-full"
                    initial={{ width: 0 }}
                    animate={{ width: `${toast.progress}%` }}
                    transition={{ duration: 0.3 }}
                  />
                </div>
              </div>
            )}
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

// Toast Container Component
export const ToastContainer = ({ children }) => {
  return (
    <div className="fixed inset-0 pointer-events-none z-50">
      <div className="pointer-events-auto">
        {children}
      </div>
    </div>
  )
}

export default Toast

import React, { createContext, useContext, useEffect, useState } from 'react'
import { supabase } from '@/services/supabase'
import { toast } from 'react-toastify'

const AuthContext = createContext()

export const useAuth = () => {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null)
  const [profile, setProfile] = useState(null)
  const [loading, setLoading] = useState(true)

  // Fetch user profile
  const fetchProfile = async (userId) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single()

      if (error) throw error
      setProfile(data)
    } catch (error) {
      console.error('Error fetching profile:', error)
    }
  }

  // Sign up
  const signUp = async (email, password, fullName) => {
    try {
      setLoading(true)

      const { data, error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: {
            full_name: fullName
          }
        }
      })

      if (error) throw error

      toast.success('Kay─▒t ba┼şar─▒l─▒! L├╝tfen e-postan─▒z─▒ do─şrulay─▒n.')
      return data
    } catch (error) {
      toast.error(error.message)
      throw error
    } finally {
      setLoading(false)
    }
  }

  // Sign in
  const signIn = async (email, password) => {
    try {
      setLoading(true)

      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password
      })

      if (error) throw error

      toast.success('Giri┼ş ba┼şar─▒l─▒!')
      return data
    } catch (error) {
      toast.error(error.message)
      throw error
    } finally {
      setLoading(false)
    }
  }

  // Sign out
  const signOut = async () => {
    try {
      await supabase.auth.signOut()
      setUser(null)
      setProfile(null)
      toast.success('├ç─▒k─▒┼ş yap─▒ld─▒')
    } catch (error) {
      toast.error('├ç─▒k─▒┼ş yap─▒lamad─▒')
      console.error('Sign out error:', error)
    }
  }

  // Reset password
  const resetPassword = async (email) => {
    try {
      const { error } = await supabase.auth.resetPasswordForEmail(email)

      if (error) throw error

      toast.success('┼Şifre s─▒f─▒rlama linki e-postan─▒za g├Ânderildi')
    } catch (error) {
      toast.error(error.message)
      throw error
    }
  }

  // Update profile
  const updateProfile = async (updates) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .update(updates)
        .eq('id', user.id)
        .select()
        .single()

      if (error) throw error

      setProfile(data)
      toast.success('Profil g├╝ncellendi')
      return data
    } catch (error) {
      toast.error('Profil g├╝ncellenemedi')
      throw error
    }
  }

  // Check if user is admin
  const isAdmin = profile?.role === 'admin'

  // Initialize auth state
  useEffect(() => {
    const initializeAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession()

        if (session?.user) {
          setUser(session.user)
          await fetchProfile(session.user.id)
        }
      } catch (error) {
        console.error('Auth initialization error:', error)
      } finally {
        setLoading(false)
      }
    }

    initializeAuth()

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        if (session?.user) {
          setUser(session.user)
          await fetchProfile(session.user.id)
        } else {
          setUser(null)
          setProfile(null)
        }
        setLoading(false)
      }
    )

    return () => subscription.unsubscribe()
  }, [])

  const value = {
    user,
    profile,
    loading,
    signUp,
    signIn,
    signOut,
    resetPassword,
    updateProfile,
    isAdmin,
    isAuthenticated: !!user
  }

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  )
}

