// Security Event Logger
export const useSecurityLogger = () => {
  const logSecurityEvent = useCallback((event, details = {}) => {
    const securityEvent = {
      timestamp: new Date().toISOString(),
      type: event,
      severity: details.severity || 'medium',
      details,
      userAgent: navigator.userAgent,
      ip: details.ip || 'unknown'
    }

    // Log to console in development
    if (process.env.NODE_ENV === 'development') {
      console.warn('Security Event:', securityEvent)
    }

    // Send to monitoring service in production
    if (process.env.NODE_ENV === 'production' && window.gtag) {
      window.gtag('event', 'security_event', {
        event_category: 'security',
        event_label: event,
        custom_parameters: securityEvent
      })
    }
  }, [])

  return {
    logSecurityEvent
  }
}

import { useState, useEffect } from 'react'
import { supabase } from '@/services/supabase'

export const useSupabaseQuery = (queryFn, dependencies = []) => {
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    let isMounted = true

    const fetchData = async () => {
      try {
        setLoading(true)
        setError(null)

        const result = await queryFn()

        if (isMounted) {
          setData(result)
        }
      } catch (err) {
        if (isMounted) {
          setError(err)
        }
      } finally {
        if (isMounted) {
          setLoading(false)
        }
      }
    }

    fetchData()

    return () => {
      isMounted = false
    }
  }, dependencies)

  const refetch = async () => {
    try {
      setLoading(true)
      setError(null)

      const result = await queryFn()
      setData(result)
    } catch (err) {
      setError(err)
    } finally {
      setLoading(false)
    }
  }

  return { data, loading, error, refetch }
}

// Real-time subscription hook
export const useSupabaseRealtime = (table, filter = '*', callback) => {
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    // Initial fetch
    const fetchInitialData = async () => {
      try {
        setLoading(true)
        const { data, error } = await supabase
          .from(table)
          .select(filter)

        if (error) throw error
        setData(data)
      } catch (error) {
        console.error('Initial fetch error:', error)
      } finally {
        setLoading(false)
      }
    }

    fetchInitialData()

    // Set up real-time subscription
    const subscription = supabase
      .channel(`${table}_changes`)
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table },
        (payload) => {
          if (callback) {
            callback(payload)
          } else {
            // Default behavior: update data based on event type
            setData(currentData => {
              switch (payload.eventType) {
                case 'INSERT':
                  return [...(currentData || []), payload.new]
                case 'UPDATE':
                  return (currentData || []).map(item => 
                    item.id === payload.new.id ? payload.new : item
                  )
                case 'DELETE':
                  return (currentData || []).filter(item => 
                    item.id !== payload.old.id
                  )
                default:
                  return currentData
              }
            })
          }
        }
      )
      .subscribe()

    return () => {
      subscription.unsubscribe()
    }
  }, [table, filter, callback])

  return { data, loading }
}

import { useState, useEffect, useRef, useMemo } from 'react'

export const useVirtualList = ({
  items,
  itemHeight = 50,
  containerHeight = 400,
  overscan = 5,
  getItemKey = (item, index) => index
}) => {
  const [scrollTop, setScrollTop] = useState(0)
  const containerRef = useRef(null)

  const visibleRange = useMemo(() => {
    const startIndex = Math.max(0, Math.floor(scrollTop / itemHeight) - overscan)
    const endIndex = Math.min(
      items.length - 1,
      Math.ceil((scrollTop + containerHeight) / itemHeight) + overscan
    )

    return { startIndex, endIndex }
  }, [scrollTop, itemHeight, containerHeight, overscan, items.length])

  const visibleItems = useMemo(() => {
    return items.slice(visibleRange.startIndex, visibleRange.endIndex + 1).map((item, index) => ({
      item,
      index: visibleRange.startIndex + index,
      key: getItemKey(item, visibleRange.startIndex + index)
    }))
  }, [items, visibleRange, getItemKey])

  const totalHeight = items.length * itemHeight

  const handleScroll = (e) => {
    setScrollTop(e.target.scrollTop)
  }

  useEffect(() => {
    const container = containerRef.current
    if (container) {
      container.addEventListener('scroll', handleScroll, { passive: true })
      return () => container.removeEventListener('scroll', handleScroll)
    }
  }, [])

  return {
    containerRef,
    visibleItems,
    totalHeight,
    itemHeight,
    containerHeight
  }
}

